    # while avoiding getting too close to opponent.
    best_move, best_val = (0, 0), -10**18
    for dx, dy in moves:
        nx, ny = sx + dx, sy + dy
        if not inside(nx, ny):
            continue
        my_next = (nx, ny)
        my_to_opp = md(my_next, (ox, oy))
        # Prefer actions that secure a resource I'm relatively closer to.
